package com.example.sociallogin

import android.app.Activity
import android.content.Intent
import android.net.Uri
import android.os.Bundle
import android.webkit.CookieManager
import android.webkit.WebResourceRequest
import android.webkit.WebView
import android.webkit.WebViewClient
import androidx.appcompat.app.AppCompatActivity
import java.net.URLEncoder
import java.util.UUID

class FacebookWebAuthActivity : AppCompatActivity() {

    private lateinit var webView: WebView
    private val state: String = UUID.randomUUID().toString()

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)

        webView = WebView(this)
        setContentView(webView)

        val scopes = intent.getStringArrayListExtra(EXTRA_SCOPES) ?: arrayListOf("public_profile", "email")

        CookieManager.getInstance().setAcceptCookie(true)
        CookieManager.getInstance().setAcceptThirdPartyCookies(webView, true)

        webView.settings.javaScriptEnabled = true
        webView.settings.domStorageEnabled = true
        webView.settings.userAgentString = webView.settings.userAgentString + " SocialLoginModule/1.0"

        webView.webViewClient = object : WebViewClient() {
            override fun shouldOverrideUrlLoading(view: WebView?, request: WebResourceRequest?): Boolean {
                val url = request?.url?.toString() ?: return false
                return handleUrl(url)
            }

            override fun shouldOverrideUrlLoading(view: WebView?, url: String?): Boolean {
                val u = url ?: return false
                return handleUrl(u)
            }

            private fun handleUrl(url: String): Boolean {
                if (url.startsWith(FacebookOAuthConfig.REDIRECT_URI)) {
                    val uri = Uri.parse(url)
                    val fragment = uri.fragment.orEmpty()
                    val query = uri.query.orEmpty()

                    val params = parseParams(fragment.ifBlank { query })
                    val returnedState = params["state"]
                    val accessToken = params["access_token"]
                    val error = params["error_description"] ?: params["error"] ?: params["error_message"]

                    if (returnedState != null && returnedState != state) {
                        finishWithError("Invalid state")
                        return true
                    }

                    if (!error.isNullOrBlank()) {
                        finishWithError(error)
                        return true
                    }

                    if (!accessToken.isNullOrBlank()) {
                        val data = Intent().apply {
                            putExtra(EXTRA_ACCESS_TOKEN, accessToken)
                        }
                        setResult(Activity.RESULT_OK, data)
                        finish()
                        return true
                    }

                    finishWithError("No access token returned")
                    return true
                }
                return false
            }
        }

        webView.loadUrl(buildAuthUrl(scopes))
    }

    private fun buildAuthUrl(scopes: List<String>): String {
        val scopeStr = URLEncoder.encode(scopes.joinToString(","), "UTF-8")
        val redirect = URLEncoder.encode(FacebookOAuthConfig.REDIRECT_URI, "UTF-8")
        val stateEnc = URLEncoder.encode(state, "UTF-8")
        return "https://www.facebook.com/v19.0/dialog/oauth" +
            "?client_id=${FacebookOAuthConfig.APP_ID}" +
            "&redirect_uri=$redirect" +
            "&response_type=token" +
            "&scope=$scopeStr" +
            "&state=$stateEnc"
    }

    private fun parseParams(s: String): Map<String, String> {
        if (s.isBlank()) return emptyMap()
        return s.split("&")
            .mapNotNull { part ->
                val idx = part.indexOf("=")
                if (idx <= 0) return@mapNotNull null
                val k = Uri.decode(part.substring(0, idx))
                val v = Uri.decode(part.substring(idx + 1))
                k to v
            }
            .toMap()
    }

    private fun finishWithError(message: String) {
        val data = Intent().apply {
            putExtra(EXTRA_ERROR, message)
        }
        setResult(Activity.RESULT_OK, data)
        finish()
    }

    companion object {
        const val EXTRA_SCOPES = "extra_scopes"
        const val EXTRA_ACCESS_TOKEN = "extra_access_token"
        const val EXTRA_ERROR = "extra_error"
    }
}